export const getRegionsByCountry = (country: string) => regionCatalog.filter(r => r.country === country);
export const getRegionsByType = (type: string) => regionCatalog.filter(r => r.type === type);
export const getRegionsByParent = (parent: string) => regionCatalog.filter(r => r.parentRegion === parent);
export const searchRegionCatalog = (query: string) => {
  const q = query.toLowerCase();
  return regionCatalog.filter(r =>
    r.name.toLowerCase().includes(q) ||
    r.aliases.some(a => a.toLowerCase().includes(q)) ||
    r.slug.includes(q)
  );
};

